head.script:
  $(document).ready(function() {
        // Find all links in .relatedContentList .article-footer
        $('.relatedContentList .article-footer a').each(function() {
            var $link = $(this);
            var href = $link.attr('href');

            // Check if href exists and contains 'http'
            if (href && href.indexOf('http') !== -1) {
                // Remove .html from the URL
                var updatedHref = href.replace(/\.html/g, '');
                $link.attr('href', updatedHref);
            }
        });
    });




function updateArticleListClasses() {
        $('.article-list.relatedContentList').each(function() {
            var $articleList = $(this);
            var tileCount = $articleList.find('.tile-container').length;

            // Check if exactly 2 tiles
            if (tileCount === 2) {
                $articleList.addClass('two-tile-content');
            } else {
                $articleList.removeClass('two-tile-content');
            }
        });
    }

    // Run on page load
    $(document).ready(function() {
        updateArticleListClasses();
    });

function updateDropdownFix(){
		setTimeout(() => {
			if (window.matchMedia('(min-width: 991px)').matches) {
				document.querySelectorAll('.headerV2 .navbar-collapse-container .nav-item').forEach(item => {
					if (!item.classList.contains('dropdown')) {
						item.classList.add('dropdown');
					}
				});
			}
		}, 300);
}
updateDropdownFix();


$(window).on('resize', function() {
	updateDropdownFix();

});

link.script:
var url = document.referrer;
if(url){
	document.getElementById("tertiary-banner-backward-arrow").href = url.substring(0, url.lastIndexOf('/'))+'.html';
}

$(document).ready(function(){
    mappingArray = [
    ["/content/dam/bnymellon/", "/assets/corporate/"],
    ["/content/dam/pershing/", "/assets/pershing/"],
    ["/content/dam/bnymellonwealth/", "/assets/wealth/"],
    ["/content/dam/im/", "/assets/investments/im/"],
    ["/content/dam/imemea/", "/assets/investments/imemea/"],
    ["/content/dam/ukadviser/", "/assets/investments/ukadviser/"],
];

    for(vi = 0; vi < mappingArray.length; vi++){
        mapObj = mappingArray[vi];
        replaceFrom = mapObj[0];
        replaceTo = mapObj[1];
        $("a[href *= '"+replaceFrom+"']").each(function(){
            path = $(this).attr('href');
            if(path.startsWith(replaceFrom)) {
            	path = path.replace(replaceFrom, replaceTo);
            	$(this).attr('href', path);
            }
        });
    }

});
